selector_to_html = {"a[href=\"#why-not-conda\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Why not <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span></code>?<a class=\"headerlink\" href=\"#why-not-conda\" title=\"Link to this heading\">#</a></h2><p>If you <strong>must</strong> use conda, <strong>only</strong> use <code class=\"docutils literal notranslate\"><span class=\"pre\">miniforge3</span></code>.\nMany recommended setup steps for miniconda/anaconda are basically mimicking the defaults of <code class=\"docutils literal notranslate\"><span class=\"pre\">miniforge3</span></code>.</p><p>If you already know conda, that\u2019s fine \u2014 just <strong>avoid mixing</strong> <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span> <span class=\"pre\">install</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span> <span class=\"pre\">install</span></code> after your initial setup unless you have to.</p>", "a[href=\"#mixing-conda-and-pip\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Mixing conda and pip<a class=\"headerlink\" href=\"#mixing-conda-and-pip\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span></code> will automatically fallback to using a conda environment if no <code class=\"docutils literal notranslate\"><span class=\"pre\">.venv/</span></code> folder is found:</p>", "a[href=\"#virtual-environment-options\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Virtual environment options<a class=\"headerlink\" href=\"#virtual-environment-options\" title=\"Link to this heading\">#</a></h2><p>You could learn the in\u2019s and out\u2019s for all of the virtual environments below.\nDon\u2019t do this (use <a class=\"reference external\" href=\"https://docs.astral.sh/uv/getting-started/\">UV</a>, the community is finally settling on a standard).</p><p>There are generally three camps:</p>", "a[href=\"#uv-commands\"]": "<table class=\"table\" id=\"uv-commands\">\n<caption><span class=\"caption-text\">Most helpful UV Commands</span><a class=\"headerlink\" href=\"#uv-commands\" title=\"Link to this table\">#</a></caption>\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p><strong>Command</strong></p></th>\n<th class=\"head\"><p><strong>Description</strong></p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">venv</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">venv</span> <span class=\"pre\">.myvenv</span></code></p></td>\n<td><p>Create an env, optionally name it myenv (not recommended)</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">sync</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">lock</span> <span class=\"pre\">--upgrade</span></code></p></td>\n<td><p>Update your environment based on the current most up to date packages</p></td>\n</tr>\n<tr class=\"row-even\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">add</span> <span class=\"pre\">&lt;package&gt;</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">remove</span> <span class=\"pre\">&lt;package&gt;</span></code></p></td>\n<td><p>Add/remove packages (updates <code class=\"docutils literal notranslate\"><span class=\"pre\">pyproject.toml</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">uv.lock</span></code>, and your env)</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">sync</span> <span class=\"pre\">--upgrade-package</span> <span class=\"pre\">&lt;pkg&gt;</span></code> / <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span> <span class=\"pre\">lock</span> <span class=\"pre\">--upgrade</span></code></p></td>\n<td><p>Upgrade single/all packages</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#virtual-environments\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Virtual Environments<a class=\"headerlink\" href=\"#virtual-environments\" title=\"Link to this heading\">#</a></h1><p>Most bugs and frustration in Python come from mismanaging virtual environments.</p>", "a[href=\"#how-to-prevent-environment-issues\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">How to prevent environment issues<a class=\"headerlink\" href=\"#how-to-prevent-environment-issues\" title=\"Link to this heading\">#</a></h2><p>No matter what command you\u2019re running, check the terminal outputs for a filepath that points to python.</p><p>For jupyterlab:</p>", "a[href=\"#guide-to-using-uv\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Guide to using UV<a class=\"headerlink\" href=\"#guide-to-using-uv\" title=\"Link to this heading\">#</a></h2><p><a class=\"reference external\" href=\"https://docs.astral.sh/uv/\">uv</a> is a complete drop-in replacement for <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span></code>.<br/>\nIf you know <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span></code>, you already know <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span></code>.</p><p>If you have a mess of environments, maybe you mixed <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">venv</span></code>, and <code class=\"docutils literal notranslate\"><span class=\"pre\">pyenv</span></code>, installing and using <code class=\"docutils literal notranslate\"><span class=\"pre\">uv</span></code> will\nnot conflict with your current environment.</p>", "a[href=\"#two-common-examples\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Two common examples<a class=\"headerlink\" href=\"#two-common-examples\" title=\"Link to this heading\">#</a></h2><p><strong>Mixing <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span></code></strong></p><p>You <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span> <span class=\"pre\">install</span> <span class=\"pre\">&lt;PACKAGE&gt;</span></code> as the installation instructions told you to do.\nBut you missed the <a class=\"reference external\" href=\"https://packaging.python.org/en/latest/specifications/dependency-specifiers/#extras\">extra</a> <code class=\"docutils literal notranslate\"><span class=\"pre\">[notebook]</span></code> dependency, so you <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span> <span class=\"pre\">install</span> <span class=\"pre\">jupyter</span></code>.\n<code class=\"docutils literal notranslate\"><span class=\"pre\">jupyter</span></code> is one of several libraries that will not work when mixing <code class=\"docutils literal notranslate\"><span class=\"pre\">conda</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">pip</span></code>.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
